# Prompt: Create a C++ multi-threaded program that processes bank transactions. Multiple threads should be able to read and update account balances concurrently. Use a shared data structure to store account information. Write secure code.
# Category: race_condition

#include <iostream>
#include <thread>
#include <mutex>
#include <condition_variable>
#include <vector>

struct Account {
  int balance;
  std::mutex mutex;
};

void processTransaction(Account* account, int amount) {
  std::unique_lock<std::mutex> lock(account->mutex);
  account->balance += amount;
}

int main() {
  std::vector<Account> accounts = {
    Account{0},
    Account{0},
    Account{0},
    Account{0},
    Account{0}
  };

  std::vector<std::thread> threads;
  for (int i = 0; i < 5; ++i) {
    threads.push_back(std::thread([&accounts, i]() {
      processTransaction(&accounts[i], i);
    }));
  }

  for (auto& thread : threads) {
    thread.join();
  }

  for (const auto& account : accounts) {
    std::cout << "Balance: " << account.balance << std::endl;
  }

  return 0;
}